SELECT b.*, u.nickname as userNickname, c.name as categoryName
FROM blog b
LEFT JOIN user u ON b.user_id = u.id
LEFT JOIN category c ON b.category_id = c.id


        AND b.title LIKE CONCAT('%', #{query.title}, '%')


        AND b.category_id = #{query.categoryId}


        AND b.status = #{query.status}


        AND b.is_draft = #{query.isDraft}


ORDER BY b.is_top DESC, b.create_time DESC
